class PrepareTask(TasksBase.TaskPrepare):
    def __init__(self, name, description):
        TasksBase.TaskPrepare.__init__(self, name, description)

class SolveTask(TasksBase.TaskSolve):
    def __init__(self, name, description):
        TasksBase.TaskSolve.__init__(self, name, description)

class ResultsTask(TasksBase.TaskResults):
    def __init__(self, name, description):
        TasksBase.TaskResults.__init__(self, name, description)

class FlowFemSolver(FemSolverBase):
    def __init__(self, name, description):
        FemSolverBase.__init__(self, name, description)
        self.tasks = self._getTasks()
        self.taskClasses = self._getTaskClasses()

    def _getTasks(self):
        return [
            CheckTask("Check Task", "Check the input"),
            PrepareTask("Prepare Task", "Prepare the solver"),
            SolveTask("Solve Task", "Solve the solver"),
            ResultsTask("Results Task", "Get the results"),
        ]

    def _getTaskClasses(self):
        taskClasses = [
            CheckTask,
            PrepareTask,
            SolveTask,
            ResultsTask,
        ]
        return taskClasses

def FlowFemSolverTask():
