import FreeCAD

class SceneVisualizer:
    def __init__(self):
        self.doc = FreeCAD.ActiveDocument
        self.view = self.doc.viewProvider("ActiveView")

    def show_all_scenegraph(self):
        import pivy
        scenegraph = self.view.getSceneGraph()

        for node in scenegraph:
            if node.isOfType(pivy.cointypes.SoSeparator):
                print("Separator node:")
                self.show_node(node)
            elif node.isOfType(pivy.cointypes.SoGroup):
                print("Group node:")
                self.show_node(node)
            elif node.isOfType(pivy.cointypes.SoShape):
                print("Shape node:")
                self.show_node(node)
            elif hasattr(node, 'point'):
                print("Point node:")
                print(node.point)
            elif hasattr(node, 'numPoints'):
                print("NumPoints node:")
                print(node.numPoints)
            elif hasattr(node, 'numVertices'):
                print("NumVertices node:")
                print(node.numVertices)
            elif hasattr(node, 'rgb'):
                print("RGB node:")
                print(node.rgb)
            else:
                print("Unknown node type")

    def show_node(self, node):
        print("Node type:", type(node).__name__)
        print("Node name:", node.get(name="Name"))
        if hasattr(node, 'getMatrix'):
            print("Matrix:")
            print(node.getMatrix())
        if hasattr(node, 'point'):
            print("Point:")
            print(node.point)
        if hasattr(node, 'numPoints'):
            print("Num Points:")
            print(node.numPoints)
        if hasattr(node, 'numVertices'):
            print("Num Vertices:")
            print(node.numVertices)
        if hasattr(node, 'rgb'):
            print("RGB:")
            print(node.rgb)
        if hasattr(node, 'getTransformation'):
            print("Transformation:")
            print(node.getTransformation())
        if node.isOfType(pivy.cointypes.SoShape):
            if hasattr(node, 'point'):
                pts = node.point.getValues()
                if len(pts) > 0:
                    print("Shape points:")
                    for i, (x, y, z) in enumerate(pts):
                        print(f"Point {i}: ({x}, {y}, {z})")
        if hasattr(node, 'drawStyle'):
            print("Draw style:", node.drawStyle)
        if hasattr(node, 'style'):
            print("Style:", node.style)
        if hasattr(node, 'numEdges'):
            print("Num edges:", node.numEdges)
        if hasattr(node, 'numFaces'):
            print("Num faces:", node.numFaces)
        if hasattr(node, 'numWires'):
            print("Num wires:", node.numWires)

visualizer = SceneVisualizer()
visualizer.show_all_scenegraph()
